(15, 4, 'KISSWIFE 6-Pair Gold & Pearl Geometric Hoop Earrings Set for Women & Girls', 'kisswife-6-pair-gold-pearl-geometric-hoop-earrings-set-for-women-girls', '1778645907_qsNlBgMQhW.webp', 1, 1, NULL, NULL, '<h2 class=\"pdp-mod-section-title outer-title\" data-spm-anchor-id=\"a2a0e.pdp_revamp.0.i3.6de8404egBRpLt\">Product details of</h2>\r\n<div class=\"pdp-product-detail\" data-spm=\"product_detail\">\r\n<div class=\"pdp-product-desc height-limit\">\r\n<div class=\"html-content pdp-product-highlights\">\r\n<article class=\"lzd-article\">\r\n<ul>\r\n<li>\r\n<div>Gender Women</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Style TRENDY</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Material Metal</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Metals Type Zinc Alloy</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Origin Mainland China</div>\r\n</li>\r\n<li>\r\n<div>Item Type EARRINGS</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Earring Type drop earrings</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Fine or Fashion fashion</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Name Gold Color Metal Pearl Earrings Set</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Feature good Quality</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Material Alloy,Acrylic,Resin,Pearl</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Color Picture Display</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Season Spring Summer Fall Winter</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Suit for Girls,Women</div>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li>\r\n<div>Occasion Party,Wedding,Birthday,Anniversary,Christmas Gift,Daily Wearing</div>\r\n</li>\r\n<li>\r\n<div>6 Pairs Earring set</div>\r\n</li>\r\n<li>\r\n<div>Different designs 6 pair earring set</div>\r\n</li>\r\n<li>\r\n<div>flower shape</div>\r\n</li>\r\n<li>\r\n<div>butterfly shape</div>\r\n</li>\r\n<li>\r\n<div>diamond earring</div>\r\n</li>\r\n<li>\r\n<div>small pearl earring</div>\r\n</li>\r\n<li>\r\n<div>simple earring</div>\r\n</li>\r\n<