INSERT INTO `resort_convention_halls` (`id`, `title`, `beds`, `bathrooms`, `size`, `location`, `image`, `image_thumb`, `floor_plans_image`, `status`, `activity`, `description`, `property_type`, `created_at`, `updated_at`) VALUES
(1, 'কক্সবাজার সী-ব্রিজ রিসোর্ট অ্যান্ড কনভেনশন হল', NULL, NULL, NULL, 'মেরিন ড্রাইভ রোড, কলাতলী, কক্সবাজার', '1782386757_PoLeI5GAeT.jpeg', '1782386757_PoLeI5GAeT_thumb.jpeg', NULL, 1, 1, '<p data-start=\"101\" data-end=\"523\">কক্সবাজার সী-ব্রিজ রিসোর্ট অ্যান্ড কনভেনশন হল হলো সমুদ্রের অপার সৌন্দর্য, আধুনিক স্থাপত্যশৈলী এবং উন্নত নাগরিক সুবিধার এক অনন্য সমন্বয়। বিশ্বের দীর্ঘতম সমুদ্রসৈকতের নিকটে অবস্থিত এই রিসোর্ট ও কনভেনশন হল পর্যটক, পরিবার, কর্পোরেট অতিথি এবং সামাজিক আয়োজনের জন্য একটি আদর্শ স্থান। সমুদ্রের নির্মল বাতাস, শান্ত পরিবেশ, সবুজ প্রকৃতি এবং আধুনিক সুযোগ-সুবিধা এখানে অবস্থানকে করে তোলে আরামদায়ক, নিরাপদ ও স্মরণীয়।</p>\r\n<p data-start=\"525\" data-end=\"923\">এই রিসোর্টটি এমনভাবে পরিকল্পনা করা হয়েছে, যাতে অতিথিরা একই সঙ্গে বিশ্রাম, বিনোদন এবং মানসম্মত আতিথেয়তার অভিজ্ঞতা উপভোগ করতে পারেন। পরিবার নিয়ে অবকাশ যাপন, বন্ধুবান্ধবের সঙ্গে আনন্দঘন সময় কাটানো অথবা কর্মব্যস্ত জীবনের ক্লান্তি দূর করার জন্য এটি হতে পারে একটি চমৎকার গন্তব্য। এখানে থাকবে পরিচ্ছন্ন ও আরামদায়ক কক্ষ, উন্নত সেবা, নিরাপদ পরিবেশ, সুন্দর বসার জায়গা এবং মনোরম প্রাকৃতিক দৃশ্য উপভোগের সুযোগ।</p>\r\n<p data-start=\"925\" data-end=\"1385\">কক্সবাজার সী-ব্রিজ রিসোর্ট অ্যান্ড কনভেনশন হলের সবচেয়ে গুরুত্বপূর্ণ বৈশিষ্ট্য হলো এর বহুমুখী ব্যবহারযোগ্যতা। শুধু আবাসিক সুবিধা নয়, এখানে রয়েছে আধুনিক কনভেনশন হল, যা বিয়ে, রিসেপশন, জন্মদিন, কর্পোরেট মিটিং, সেমিনার, ট্রেনিং প্রোগ্রাম, সাংস্কৃতিক অনুষ্ঠান এবং বিভিন্ন পারিবারিক আয়োজনের জন্য উপযুক্ত। প্রশস্ত হলরুম, সুন্দর ইন্টেরিয়র, মানসম্মত লাইটিং, উন্নত সাউন্ড সিস্টেম এবং পর্যাপ্ত আসন ব্যবস্থার মাধ্যমে প্রতিটি আয়োজনকে সফল ও আকর্ষণীয় করে তোলার ব্যবস্থা থাকবে।</p>\r\n<p data-start=\"1387\" data-end=\"1678\">কর্পোরেট প্রতিষ্ঠানগুলোর জন্য এই কনভেনশন হল হতে পারে একটি আদর্শ ভেন্যু। অফিসিয়াল মিটিং, প্রেজেন্টেশন, ওয়ার্কশপ, কনফারেন্স বা টিম রিট্রিট আয়োজনের জন্য এখানে থাকবে প্রয়োজনীয় সুবিধা ও পেশাদার পরিবেশ। একই সঙ্গে সমুদ্রের কাছাকাছি অবস্থান কর্মীদের মানসিক প্রশান্তি ও নতুন উদ্যম এনে দিতে সহায়ক হবে।</p>\r\n<p data-start=\"1680\" data-end=\"2029\">সামাজিক অনুষ্ঠানের ক্ষেত্রেও এই রিসোর্ট অ্যান্ড কনভেনশন হল একটি নির্ভরযোগ্য নাম হতে পারে। জীবনের বিশেষ মুহূর্ত যেমন বিয়ে, বাগদান, বিবাহবার্ষিকী বা পারিবারিক মিলনমেলা আয়োজনের জন্য এখানে পাওয়া যাবে সৌন্দর্য, স্বাচ্ছন্দ্য ও মর্যাদাপূর্ণ পরিবেশ। অতিথিদের অভ্যর্থনা, বসার ব্যবস্থা, অনুষ্ঠান পরিচালনা এবং সামগ্রিক পরিবেশ প্রতিটি আয়োজনকে করে তুলবে স্মরণীয়।</p>\r\n<p data-start=\"2031\" data-end=\"2452\" data-is-last-node=\"\" data-is-only-node=\"\">নিরাপত্তা, পরিচ্ছন্নতা এবং অতিথি সন্তুষ্টিকে সর্বোচ্চ গুরুত্ব দিয়ে এই রিসোর্ট পরিচালিত হবে। আধুনিক সুবিধা, মনোরম পরিবেশ এবং সহজ যোগাযোগব্যবস্থার কারণে এটি কক্সবাজারে একটি আকর্ষণীয় আবাসন ও অনুষ্ঠান আয়োজন কেন্দ্র হিসেবে গড়ে উঠবে। যারা সমুদ্রের কাছাকাছি থেকে আরামদায়ক অবকাশ, মানসম্মত সেবা এবং সুন্দর আয়োজনের অভিজ্ঞতা পেতে চান, তাদের জন্য কক্সবাজার সী-ব্রিজ রিসোর্ট অ্যান্ড কনভেনশন হল হতে পারে একটি সঠিক ও নির্ভরযোগ্য ঠিকানা।</p>', NULL, '2026-05-19 00:24:30', '2026-06-25 05:25:58'),
(2, 'খাগড়াছড়ি হিল ভিউ রিসোর্ট অ্যান্ড কনভেনশন হল', NULL, NULL, NULL, 'আলুটিলা পর্যটন এলাকার নিকট, খাগড়াছড়ি সদর, খাগড়াছড়ি', '1782386749_xiUwQCpqXj.jpeg', '1782386749_xiUwQCpqXj_thumb.jpeg', NULL, 1, 1, '<p data-start=\"126\" data-end=\"623\">খাগড়াছড়ি হিল ভিউ রিসোর্ট অ্যান্ড কনভেনশন হল হলো পাহাড়, সবুজ প্রকৃতি, শান্ত পরিবেশ এবং আধুনিক সুযোগ-সুবিধার এক সুন্দর সমন্বয়। প্রাকৃতিক সৌন্দর্যে ঘেরা খাগড়াছড়ি বাংলাদেশের অন্যতম মনোরম পার্বত্য জেলা। এখানকার পাহাড়ি দৃশ্য, মেঘের ছোঁয়া, সবুজ বনভূমি, ঝরনা, নির্মল বাতাস এবং শান্ত পরিবেশ পর্যটকদের মনে এক বিশেষ অনুভূতি সৃষ্টি করে। এই অপার সৌন্দর্যের মাঝে গড়ে ওঠা খাগড়াছড়ি হিল ভিউ রিসোর্ট অ্যান্ড কনভেনশন হল অতিথিদের জন্য হতে পারে বিশ্রাম, বিনোদন এবং অনুষ্ঠান আয়োজনের একটি আদর্শ স্থান।</p>\r\n<p data-start=\"625\" data-end=\"1012\">এই রিসোর্টটি এমনভাবে পরিকল্পনা করা হয়েছে, যাতে অতিথিরা প্রকৃতির কাছাকাছি থেকে আধুনিক জীবনযাপনের প্রয়োজনীয় সুবিধাগুলো উপভোগ করতে পারেন। পরিবার নিয়ে অবকাশ যাপন, বন্ধুদের সঙ্গে আনন্দঘন সময় কাটানো, কর্পোরেট ট্যুর, অফিসিয়াল মিটিং অথবা বিশেষ কোনো সামাজিক অনুষ্ঠান আয়োজনের জন্য এটি একটি চমৎকার গন্তব্য। পাহাড়ের নীরবতা, সবুজ পরিবেশ এবং মনোরম দৃশ্য এখানে অবস্থানকে করে তোলে প্রশান্তিময় ও স্মরণীয়।</p>\r\n<p data-start=\"1014\" data-end=\"1379\">রিসোর্টে থাকবে আরামদায়ক কক্ষ, পরিচ্ছন্ন পরিবেশ, নিরাপদ আবাসন ব্যবস্থা, সুন্দর বসার জায়গা এবং অতিথি সেবার মানসম্মত আয়োজন। যারা কর্মব্যস্ত জীবনের চাপ থেকে কিছুটা দূরে গিয়ে শান্ত পরিবেশে সময় কাটাতে চান, তাদের জন্য এই রিসোর্ট হতে পারে একটি উপযুক্ত ঠিকানা। সকালে পাহাড়ি বাতাস, বিকেলে সূর্যাস্তের সৌন্দর্য এবং রাতে নিরিবিলি পরিবেশ অতিথিদের মনে এনে দেবে প্রশান্তি ও আনন্দ।</p>\r\n<p data-start=\"1381\" data-end=\"1807\">খাগড়াছড়ি হিল ভিউ কনভেনশন হলটি বিয়ে, রিসেপশন, জন্মদিন, পারিবারিক অনুষ্ঠান, সাংস্কৃতিক আয়োজন, কর্পোরেট মিটিং, সেমিনার, ট্রেনিং প্রোগ্রাম এবং কনফারেন্স আয়োজনের জন্য উপযোগী। প্রশস্ত হলরুম, সুন্দর ইন্টেরিয়র, উন্নত লাইটিং, মানসম্মত সাউন্ড সিস্টেম এবং পর্যাপ্ত আসন ব্যবস্থার মাধ্যমে প্রতিটি আয়োজনকে আকর্ষণীয় ও সফল করে তোলার ব্যবস্থা থাকবে। অতিথিদের স্বাচ্ছন্দ্য, নিরাপত্তা এবং সুশৃঙ্খল ব্যবস্থাপনাকে এখানে সর্বোচ্চ গুরুত্ব দেওয়া হবে।</p>\r\n<p data-start=\"1809\" data-end=\"2157\">কর্পোরেট প্রতিষ্ঠানগুলোর জন্য এই রিসোর্ট অ্যান্ড কনভেনশন হল হতে পারে একটি আদর্শ রিট্রিট ভেন্যু। অফিসিয়াল মিটিং, টিম বিল্ডিং প্রোগ্রাম, ওয়ার্কশপ বা বার্ষিক সম্মেলনের জন্য পাহাড়ি শান্ত পরিবেশ কর্মীদের নতুন উদ্যম ও মানসিক প্রশান্তি এনে দিতে সহায়ক হবে। একই সঙ্গে পর্যটন ও অনুষ্ঠান আয়োজনের সুবিধা এক জায়গায় থাকায় এটি অতিথিদের জন্য আরও আকর্ষণীয় হয়ে উঠবে।</p>\r\n<p data-start=\"2159\" data-end=\"2538\" data-is-last-node=\"\" data-is-only-node=\"\">সামাজিক অনুষ্ঠান আয়োজনের ক্ষেত্রেও এই স্থানটি হতে পারে একটি মর্যাদাপূর্ণ ও সুন্দর ভেন্যু। জীবনের বিশেষ মুহূর্ত যেমন বিয়ে, বাগদান, বিবাহবার্ষিকী বা পারিবারিক মিলনমেলা পাহাড়ি পরিবেশে আয়োজন করলে তা হয়ে উঠবে আরও স্মরণীয়। প্রাকৃতিক সৌন্দর্য, আধুনিক সুবিধা এবং মানসম্মত সেবার সমন্বয়ে খাগড়াছড়ি হিল ভিউ রিসোর্ট অ্যান্ড কনভেনশন হল আপনার ভ্রমণ, বিশ্রাম ও অনুষ্ঠান আয়োজনকে দেবে নতুন মাত্রা।</p>', NULL, '2026-05-19 00:45:05', '2026-06-25 05:25:49'),
(3, 'সিলেট গ্রীন ভ্যালি রিসোর্ট অ্যান্ড কনভেনশন হল', NULL, NULL, NULL, 'জাফলং রোড, সিলেট সদর, সিলেট', '1782386740_L9loIJyf3M.jpeg', '1782386740_L9loIJyf3M_thumb.jpeg', NULL, 1, 1, '<p data-start=\"105\" data-end=\"515\">সিলেট গ্রীন ভ্যালি রিসোর্ট অ্যান্ড কনভেনশন হল হলো প্রাকৃতিক সৌন্দর্য, আধুনিক স্থাপত্য এবং উন্নত আতিথেয়তার এক অনন্য সমন্বয়। চা-বাগান, সবুজ পাহাড়, স্বচ্ছ নদী, ঝরনা এবং মায়াবী প্রকৃতির জন্য সিলেট বাংলাদেশের অন্যতম জনপ্রিয় পর্যটন এলাকা। এই সৌন্দর্যমণ্ডিত পরিবেশে অবস্থিত সিলেট গ্রীন ভ্যালি রিসোর্ট অ্যান্ড কনভেনশন হল পরিবার, পর্যটক, কর্পোরেট অতিথি এবং সামাজিক অনুষ্ঠানের জন্য একটি আদর্শ গন্তব্য।</p>\r\n<p data-start=\"517\" data-end=\"977\">এই রিসোর্টটি এমনভাবে পরিকল্পনা করা হয়েছে, যাতে অতিথিরা প্রকৃতির কাছাকাছি থেকে আধুনিক সুযোগ-সুবিধা উপভোগ করতে পারেন। কর্মব্যস্ত জীবনের ক্লান্তি দূর করে শান্ত, নিরাপদ ও মনোরম পরিবেশে সময় কাটানোর জন্য এটি একটি চমৎকার স্থান। এখানে থাকবে আরামদায়ক আবাসন ব্যবস্থা, পরিচ্ছন্ন পরিবেশ, সুন্দর বসার জায়গা, নিরাপত্তা ব্যবস্থা এবং মানসম্মত অতিথি সেবা। পরিবার নিয়ে অবকাশ যাপন, বন্ধুদের সঙ্গে ভ্রমণ অথবা ব্যক্তিগত বিশ্রামের জন্য এই রিসোর্ট অতিথিদের দেবে প্রশান্তিময় অভিজ্ঞতা।</p>\r\n<p data-start=\"979\" data-end=\"1321\">সিলেট গ্রীন ভ্যালি কনভেনশন হলটি বিয়ে, রিসেপশন, জন্মদিন, পারিবারিক অনুষ্ঠান, সাংস্কৃতিক আয়োজন, কর্পোরেট মিটিং, সেমিনার, ট্রেনিং প্রোগ্রাম এবং কনফারেন্স আয়োজনের জন্য উপযুক্ত। প্রশস্ত হলরুম, আধুনিক ইন্টেরিয়র, উন্নত লাইটিং, মানসম্মত সাউন্ড সিস্টেম এবং পর্যাপ্ত আসন ব্যবস্থার মাধ্যমে প্রতিটি আয়োজনকে সফল, সুন্দর ও স্মরণীয় করে তোলার ব্যবস্থা থাকবে।</p>\r\n<p data-start=\"1323\" data-end=\"1703\">কর্পোরেট প্রতিষ্ঠানগুলোর জন্য এই রিসোর্ট অ্যান্ড কনভেনশন হল হতে পারে একটি আদর্শ রিট্রিট ভেন্যু। অফিসিয়াল মিটিং, ওয়ার্কশপ, টিম বিল্ডিং প্রোগ্রাম অথবা বার্ষিক সম্মেলনের জন্য সিলেটের শান্ত ও সবুজ পরিবেশ কর্মীদের নতুন উদ্যম এনে দিতে সহায়ক হবে। একই জায়গায় আবাসন, খাবার, অনুষ্ঠান আয়োজন এবং প্রাকৃতিক পরিবেশ উপভোগের সুবিধা থাকায় এটি কর্পোরেট ও ব্যক্তিগত&mdash;দুই ধরনের আয়োজনের জন্যই আকর্ষণীয়।</p>\r\n<p data-start=\"1705\" data-end=\"2094\" data-is-last-node=\"\" data-is-only-node=\"\">সামাজিক অনুষ্ঠানের ক্ষেত্রেও এই ভেন্যুটি হতে পারে একটি মর্যাদাপূর্ণ ঠিকানা। জীবনের বিশেষ মুহূর্ত যেমন বিয়ে, বাগদান, বিবাহবার্ষিকী বা পারিবারিক মিলনমেলা সিলেটের মনোরম প্রকৃতির মাঝে আয়োজন করলে তা হয়ে উঠবে আরও স্মরণীয়। সবুজ প্রকৃতি, আধুনিক সুবিধা, নিরাপদ পরিবেশ এবং মানসম্মত সেবার সমন্বয়ে সিলেট গ্রীন ভ্যালি রিসোর্ট অ্যান্ড কনভেনশন হল আপনার ভ্রমণ, বিশ্রাম ও অনুষ্ঠান আয়োজনকে দেবে নতুন মাত্রা।</p>', NULL, '2026-05-19 00:47:00', '2026-06-25 05:25:40');
