INSERT INTO `service_categories` (`id`, `title`, `image`, `activity`, `description`, `created_at`, `updated_at`) VALUES
(1, 'মাইক্রোসিটি', '1782384444_ZHOZ8dm2jn.webp', 1, 'মাইক্রোসিটি আধুনিক পরিকল্পনা, নিরাপদ অবকাঠামো ও সবুজ পরিবেশের সমন্বয়ে গড়ে ওঠা স্মার্ট আবাসন প্রকল্প, যেখানে উন্নত জীবনযাপনের সব সুবিধা থাকবে।', '2026-06-25 04:45:18', '2026-06-25 04:47:25'),
(2, '৫ স্টার হোটেল', '1782384482_dauo0t76yp.webp', 1, '৫ স্টার হোটেল আধুনিক বিলাসিতা, নিরাপদ পরিবেশ ও বিশ্বমানের সেবার সমন্বয়ে অতিথিদের আরামদায়ক, স্মরণীয় এবং মর্যাদাপূর্ণ থাকার অভিজ্ঞতা নিশ্চিত করে।', '2026-06-25 04:48:02', '2026-06-25 04:48:02'),
(3, 'রিসোর্ট ও কনভেনশন হল', '1782384524_CGkwbf6pF4.webp', 1, 'রিসোর্ট ও কনভেনশন হল প্রাকৃতিক সৌন্দর্য, আধুনিক আয়োজন ও আরামদায়ক পরিবেশে বিনোদন, কর্পোরেট ইভেন্ট এবং স্মরণীয় অনুষ্ঠানের সেবা প্রদান করে।', '2026-06-25 04:48:45', '2026-06-25 04:48:45');
