INSERT INTO `special_goals` (`id`, `title`, `description`, `serial`, `status`, `activity`, `created_at`, `updated_at`) VALUES
(1, 'উন্নত সেবা নিশ্চিত করা', 'মানসম্মত ও আধুনিক সেবার মাধ্যমে গ্রাহকদের সর্বোচ্চ সন্তুষ্টি নিশ্চিত করা আমাদের অঙ্গীকার।', 1, 1, 1, '2026-06-25 02:28:29', '2026-06-25 02:28:42'),
(2, 'নিরাপদ ও আরামদায়ক পরিবেশ তৈরি করা', 'সবার জন্য নিরাপদ, পরিচ্ছন্ন ও আরামদায়ক পরিবেশ নিশ্চিত করে জীবনমান উন্নয়নে কাজ করা।', 2, 1, 1, '2026-06-25 02:29:08', '2026-06-25 02:29:08'),
(3, 'পর্যটন খাতকে সমৃদ্ধ করা', 'দেশীয় ও আন্তর্জাতিক পর্যটন শিল্পের বিকাশে আধুনিক ও আকর্ষণীয় সুযোগ-সুবিধা গড়ে তোলা।', 3, 1, 1, '2026-06-25 02:29:29', '2026-06-25 02:29:29'),
(4, 'কর্মমুখী উদ্যোক্তা তৈরি করা', 'নতুন উদ্যোক্তা তৈরি এবং দক্ষ মানবসম্পদ গড়ে তুলে অর্থনৈতিক উন্নয়নে অবদান রাখা।', 4, 1, 1, '2026-06-25 02:29:47', '2026-06-25 02:29:47'),
(5, 'কর্মসংস্থান সৃষ্টি করা', 'নতুন কর্মসংস্থানের সুযোগ সৃষ্টি করে দেশের আর্থ-সামাজিক উন্নয়নে গুরুত্বপূর্ণ ভূমিকা পালন করা।', 5, 1, 1, '2026-06-25 02:30:02', '2026-06-25 02:30:02'),
(6, 'টেকসই উন্নয়ন নিশ্চিত করা', 'দীর্ঘমেয়াদী পরিকল্পনা ও আধুনিক ব্যবস্থাপনার মাধ্যমে টেকসই উন্নয়ন এবং সামাজিক কল্যাণ নিশ্চিত করা।', 6, 1, 1, '2026-06-25 02:30:19', '2026-06-25 02:30:19');
