INSERT INTO `visions` (`id`, `title`, `activity`, `created_at`, `updated_at`) VALUES
(1, 'আরব গ্রুপ উদ্যোক্তা মনোভাব, পরিবেশ সচেতনতা এবং আধুনিক পরিকল্পনার মাধ্যমে দেশের অর্থনৈতিক ও সামাজিক উন্নয়নকে এগিয়ে নেওয়াই আমাদের মূল উদ্দেশ্য।', 1, '2026-06-25 02:56:48', '2026-06-25 02:57:29'),
(2, 'আরব গ্রুপ বিশ্বাস করে, মানুষের উন্নয়নের মধ্য দিয়েই দেশের প্রকৃত উন্নয়ন সম্ভব।', 1, '2026-06-25 02:57:43', '2026-06-25 02:57:43'),
(3, 'আরব গ্রুপ শুধু ব্যবসা করে না; উদ্যোক্তা তৈরি, কর্মসংস্থান সৃষ্টি এবং বৈদেশিক মুদ্রা অর্জনের মাধ্যমে একটি শক্তিশালী অর্থনৈতিক ইকোসিস্টেম গড়ে তোলে।', 1, '2026-06-25 02:57:50', '2026-06-25 02:57:50'),
(4, 'দেশে-বিদেশে চাকরি খোঁজার মানসিকতা থেকে বেরিয়ে নতুন ব্যবসা ও স্টার্টআপ চালু করতে তরুণদের উৎসাহিত করা।', 1, '2026-06-25 02:57:58', '2026-06-25 02:57:58'),
(5, 'পর্যাপ্ত প্রশিক্ষণ, পুঁজি, মেন্টরশিপ এবং বৈশ্বিক বাজার সংযোগে সহায়তা দেওয়া।', 1, '2026-06-25 02:58:07', '2026-06-25 02:58:07'),
(6, 'প্রযুক্তিগত ও কারিগরি দক্ষতা অর্জনের মাধ্যমে তরুণদের উদ্যোক্তা হিসেবে গড়ে তোলা এবং দেশ ও সমাজ গঠনে তাদের সক্রিয় অংশগ্রহণ নিশ্চিত করা।', 1, '2026-06-25 02:58:14', '2026-06-25 02:58:14'),
(7, 'তরুণদের চিন্তাভাবনা, সৃজনশীলতা এবং প্রযুক্তির সঠিক ব্যবহার নিশ্চিত করে দেশের অর্থনৈতিক ও সামাজিক উন্নয়ন ত্বরান্বিত করা।', 1, '2026-06-25 02:58:21', '2026-06-25 02:58:21'),
(8, 'বাংলাদেশের প্রতিটি জেলা শহরে পরিকল্পিত ও আধুনিক আবাসিক এলাকা গড়ে তোলা এবং পর্যটন কেন্দ্রগুলোকে পরিবেশবান্ধব করে দেশের সৌন্দর্যকে বিশ্ব দরবারে মডেল হিসেবে তুলে ধরা।', 1, '2026-06-25 02:58:27', '2026-06-25 02:58:27'),
(9, 'দেশের সৌন্দর্য সংরক্ষণ, পরিবেশ রক্ষা এবং মানুষের জীবনমান উন্নয়নের লক্ষ্যে নিরলসভাবে কাজ করা।', 1, '2026-06-25 02:58:35', '2026-06-25 02:58:35'),
(10, 'ব্যাচেলর গ্রুপ শুধু একটি কোম্পানি নয়; এটি কোটি মানুষের আশা, একটি সুন্দর, উন্নত, টেকসই ও মানবিক বাংলাদেশের স্বপ্ন।', 1, '2026-06-25 02:58:41', '2026-06-25 02:58:41'),
(11, 'দেশের উন্নয়ন শুধু অবকাঠামোতে নয়; মানুষের মানসিকতা, শিক্ষা, দক্ষতা, সচেতনতা এবং পারস্পরিক সহযোগিতার মাধ্যমেই প্রকৃত উন্নয়ন সম্ভব।', 1, '2026-06-25 02:58:48', '2026-06-25 02:58:48'),
(12, 'এরই ধারাবাহিকতায় ব্যাচেলর গ্রুপ দেশের সৌন্দর্য বৃদ্ধি ও মানব উন্নয়নের পথে দৃঢ় প্রতিজ্ঞায় এগিয়ে চলছে।', 1, '2026-06-25 02:58:55', '2026-06-25 02:58:55');
